using Aspose.Pdf.Facades;
using System.Collections.Generic;

void ValidateAndImport(string pdfPath, DataTable data)
{
    using (Form form = new Form(pdfPath))
    {
        List<string> missing = new List<string>();
        foreach (string name in form.FieldNames)
            if (form.IsRequiredField(name) && !data.Columns.Contains(name))
                missing.Add(name);
        if (missing.Count > 0)
            throw new InvalidOperationException($"Missing required fields: {string.Join(", ", missing)}");
        // proceed with AutoFiller import...
    }
}

