clear-readonly-before-savenewinfo.code:
try {
    pdfInfo.SaveNewInfo(outputPath);
} catch (IOException io) when (io.Message.IndexOf("read-only", StringComparison.OrdinalIgnoreCase) >= 0) {
    var fi = new FileInfo(outputPath);
    if (fi.IsReadOnly) {
        fi.IsReadOnly = false;
        fi.Attributes = FileAttributes.Normal;
    }
    pdfInfo.SaveNewInfo(outputPath);
} catch (UnauthorizedAccessException) {
    var fi = new FileInfo(outputPath);
    if (fi.IsReadOnly) {
        fi.IsReadOnly = false;
        fi.Attributes = FileAttributes.Normal;
    }
    pdfInfo.SaveNewInfo(outputPath);
}

