    var type = pdfObject.GetType();
    var field = type.GetField("_objectId", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
    if (field != null) return field.GetValue(pdfObject)?.ToString() ?? "N/A";
    var prop = type.GetProperty("ObjectId", System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
