    {
        if (pdf.Form.HasField(name))
        {
            WidgetAnnotation widget = pdf.Form[name];
            using var ms = new MemoryStream();
            widget.ExportToJson(ms);
            fragments.Add(Encoding.UTF8.GetString(ms.ToArray()));
        }
    }
    string json = "[" + string.Join(",", fragments) + "]";
    File.WriteAllText("selected.json", json, Encoding.UTF8);
}

